/**
 * Helper function to calculate the 7 target indices (k_0 to k_6) in the 4x4 grid (0-15).
 * The sequence starts at (0, 0).
 */
function calculateTargetIndices(directions) {
    let r = 0;
    let c = 0;
    const indices = [0]; // k_0 = 0*4 + 0 (Starting cell)

    for (let i = 0; i < 6; i++) {
        if (directions[i] === 'D') {
            r += 1;
        } else if (directions[i] === 'R') {
            c += 1;
        }
        indices.push(r * 4 + c);
    }
    return indices;
}

/**
 * Counts the number of good integers x in the range [0, N_bigint] based on the required digit constraints.
 */
function solve_up_to(N_bigint, K, K_map) {
    if (N_bigint < 0n) return 0n;

    // Convert N to a 16-digit padded string representation S
    let S_str = N_bigint.toString();
    const M = 16; 
    S_str = S_str.padStart(M, '0');

    // Memoization: Map key: `${i}:${tight}:${V_last}`
    const memo = new Map();

    // V_last: The value of the last required digit encountered in K (0-9). 
    // Initialized to 0, ensuring D_0 >= 0.
    function dp(i, tight, V_last) {
        if (i === M) {
            return 1n; // Found one valid 16-digit representation
        }

        const key = `${i}:${tight}:${V_last}`;
        if (memo.has(key)) {
            return memo.get(key);
        }

        const limit = tight ? parseInt(S_str[i]) : 9;
        let count = 0n;

        for (let d = 0; d <= limit; d++) {

            let new_V_last = V_last;
            let isValid = true;

            // Check if the current index i is one of the required indices k_j
            if (K_map.has(i)) {
                // Constraint: Current digit d must be >= V_last (Non-decreasing requirement)
                if (d < V_last) {
                    isValid = false;
                } else {
                    // Update V_last because this digit is required by the path
                    new_V_last = d;
                }
            }

            if (isValid) {
                const new_tight = tight && (d === limit);
                count += dp(i + 1, new_tight, new_V_last);
            }
        }

        memo.set(key, count);
        return count;
    }

    // Initial call: i=0, tight=true, V_last=0
    return dp(0, true, 0);
}

function solve(l, r, directions) {
    const L_big = BigInt(l);
    const R_big = BigInt(r);

    // Step 1: Calculate target indices K
    const K = calculateTargetIndices(directions);

    // Step 2: Create map for O(1) lookup
    const K_map = new Map();
    K.forEach((k, index) => {
        K_map.set(k, index);
    });

    // Step 3: Calculate count(R) - count(L-1)

    // Count in [0, R]
    const count_R = solve_up_to(R_big, K, K_map);

    // Count in [0, L-1]
    const L_minus_1_big = L_big - 1n;
    const count_L_minus_1 = solve_up_to(L_minus_1_big, K, K_map);

    // The difference gives count in [L, R]. 
    let result = count_R - count_L_minus_1;

    return Number(result);
}

