long long solve_up_to(const string& S_str, const map<int, int>& K_map) {
    const int M = 16; 
    // Memoization: Key: `${i}:${tight}:${V_last}`
    // Using map<tuple<int, bool, int>, long long> equivalent structure
    map<tuple<int, bool, int>, long long> memo;

    // dp(i, tight, V_last): counts valid suffixes starting from digit position i.
    // V_last: The value of the last digit required by the path K (0-9).
    function<long long(int, bool, int)> dp = 
