            if (isValid) {
                bool new_tight = tight && (d == limit);
                count += dp(i + 1, new_tight, new_V_last);
            }
        }

        memo[key] = count;
        return count;
    };

    // Initial call: i=0, tight=true, V_last=0
    return dp(0, true, 0);
}

