long long solve(long long l, long long r, const string& directions) {

    // Step 1: Calculate target indices K
    vector<int> K = calculateTargetIndices(directions);

    // Step 2: Create map for O(1) lookup
    map<int, int> K_map;
    for (int i = 0; i < K.size(); ++i) {
        K_map[K[i]] = i; // Map index position (0-15) to sequence position (0-6)
    }

    // Step 3: Calculate count(R) - count(L-1)

    // Count in [0, R]
    string R_str = to_string(r);
    string R_padded = string(16 - R_str.length(), '0') + R_str;
    long long count_R = solve_up_to(R_padded, K_map);

    // Count in [0, L-1]
    long long L_minus_1 = l - 1;
    string count_L_minus_1 = "0";

    if (L_minus_1 < 0) {
        count_L_minus_1 = "0";
    } else {
        string L_m1_str = to_string(L_minus_1);
        string L_m1_padded = string(16 - L_m1_str.length(), '0') + L_m1_str;
        count_L_minus_1 = to_string(solve_up_to(L_m1_padded, K_map));
