// Helper function to calculate the 7 target indices (k_0 to k_6) in the 4x4 grid (0-15).
fn calculateTargetIndices(directions: String) -> Array[Int] {
    var r: Int = 0
    var c: Int = 0
    var indices: Array[Int] = []

    // k_0 is the starting cell (0, 0)
    indices.push(r * 4 + c)

    // Apply 6 directions
    for i in 0..5 {
        if directions[i] == 'D' {
            r += 1
        } else if directions[i] == 'R' {
            c += 1
        }
        indices.push(r * 4 + c)
    }
    return indices
}

// Counts the number of good integers x in the range [0, N] based on the required digit constraints.
fn solveUpTo(N: Int64, K_indices: Array[Int]) -> Int64 {
    if N < 0 { return 0 }

    // Convert N to a 16-digit padded string representation S
    let S_str = N.to_string().pad_left(16, '0')
    let M: Int = 16

    // Memoization: Map key: "${i}:${tight}:${V_last}"
    // Map structure: [Int, Bool, Int] -> Int64 (Count)
    var memo: Hash[Tuple[Int, Bool, Int], Int64] = {}

    // Create map for O(1) lookup of required path indices
    var K_map: Hash[Int, Bool] = {}
    for index in K_indices {
        K_map[index] = true
    }

    // dp(i, tight, V_last)
    // i: current digit position (0..15)
    // tight: restricted by N's digits
    // V_last: the value of the last required digit encountered (0-9)
    fn dp(i: Int, tight: Bool, V_last: Int) -> Int64 {
        if i == M {
            return 1
        }

        let key = Tuple[i, tight, V_last]
        if memo.contains?(key) {
            return memo[key]!
        }

        let limit = tight ? S_str[i].to_int : 9
        var count: Int64 = 0

        for d in 0..limit {

            var new_V_last = V_last
            var isValid: Bool = true

            // Check if the current index i is one of the required indices k_j
            if K_map.contains?(i) {
                // Constraint: Current digit d must be >= V_last (Non-decreasing requirement)
                if d < V_last {
                    isValid = false
                } else {
                    // Update V_last because this digit is required by the path
                    new_V_last = d
                }
            }

            if isValid {
                let new_tight = tight && (d == limit)
                count += dp(i + 1, new_tight, new_V_last)
            }
        }

        memo[key] = count
        return count
    }

    // Initial call: i=0, tight=true, V_last=0
    return dp(0, true, 0)
}

fn solve(l: Int64, r: Int64, directions: String) -> Int64 {
    // Step 1: Calculate target indices K
    let K_indices = calculateTargetIndices(directions)

    // Step 2: Calculate count(R) - count(L-1)

    // Count in [0, R]
    let count_R = solveUpTo(r, K_indices)

    // Count in [0, L-1]
    let l_minus_1: Int64 = l - 1
    let count_L_minus_1 = solveUpTo(l_minus_1, K_indices)

    let result: Int64 = count_R - count_L_minus_1

